import ast, json

allowed_raw = '''${allowed_users}'''.strip()
if allowed_raw.startswith('{'):
    try:
        allowed_raw = str(ast.literal_eval(allowed_raw).get('default', ''))
    except Exception:
        allowed_raw = ''
allowed_users = {item.strip() for item in allowed_raw.split(',') if item.strip()}
user_id = attributes.get('telegram.user_id', '').strip()
chat_id = attributes.get('telegram.chat_id', '').strip()
username = attributes.get('telegram.username', '').strip()
first_name = attributes.get('telegram.first_name', '').strip()
message_type = attributes.get('telegram.message_type', '').strip()
callback_data = attributes.get('telegram.callback_data', '').strip()
text = content.strip()

def set_reply(body, markup=None, flow_file=flow_file):
    flow_file.content = body.encode('utf-8')
    if markup:
        flow_file.set_attribute('telegram.reply_markup', json.dumps(markup))

def help_text():
    return (
        'Commands:\n'
        '/start - Show this menu\n'
        '/hello - Say hello\n'
        '/ping - Health check\n'
        '/whoami - Show Telegram IDs'
    )

if allowed_users and user_id not in allowed_users:
    set_reply('Access denied. Your Telegram user ID is ' + (user_id or 'unknown') + '.')
elif message_type == 'callback_query' and callback_data == 'hello':
    name = first_name or username or user_id or 'there'
    set_reply('Hello ' + name + '.')
else:
    command = text.split(None, 1)[0].lower() if text else ''
    if command in ('/start', '/help'):
        set_reply(help_text(), {
            'inline_keyboard': [[
                {'text': 'Say hello', 'callback_data': 'hello'},
                {'text': 'Who am I?', 'callback_data': 'whoami'}
            ]]
        })
    elif command == '/hello':
        name = first_name or username or user_id or 'there'
        set_reply('Hello ' + name + '.')
    elif command == '/ping':
        set_reply('pong')
    elif command == '/whoami' or (message_type == 'callback_query' and callback_data == 'whoami'):
        set_reply('Telegram user: ' + (user_id or 'unknown') + '\nChat: ' + (chat_id or 'unknown'))
    else:
        set_reply('Unknown command. Send /help for available commands.')
